const body = $input.first().json.body || $input.first().json;

// 1. Verifica se o objeto de mensagem existe
if (!body?.message) return [];

// 2. Ignora se a mensagem foi enviada por você mesmo
//if (body.message.fromMe === true) return [];

// 3. Ignora mensagens de grupo
if (body.message.isGroup === true) return [];

// 4. Extrai o número de telefone (limpando sufixos e caracteres não numéricos)
const rawPhone = body.message.sender_pn || body.chat?.phone || '';
const phone = rawPhone.replace('@s.whatsapp.net', '').replace(/\D/g, '');

// 5. Extrai o texto da mensagem
const message = body.message.text || body.message.content || '';

// 6. Extrai o nome do contato e o nome da instância
const name = body.message.senderName || body.chat?.wa_name || 'Desconhecido';
const instance = body.instanceName || '';

// 7. Se não tiver telefone ou mensagem, encerra
if (!phone || !message.trim()) return [];

return [{ 
  json: { 
    phone, 
    message: message.trim(), 
    name, 
    instance 
  } 
}];

const integrations = $input.first().json;
const extracted = $('Extrair Dados da Mensagem1').first().json;

const i = integrations;

return [{ json: { ...extracted, company_id: i.company_id, uazapi_base_url: i.uazapi_base_url, uazapi_token: i.uazapi_token, uazapi_instance: i.uazapi_instance, webhook_secret: i.webhook_secret } }];

// 1. RECUPERAÇÃO DE DADOS DOS NÓS ANTERIORES
// Pega a saída (output) do nó de contexto da empresa
const ctx = $('Montar Contexto da Empresa1').first().json;
// Pega a saída do nó com as configurações (mensagens, horários, etc)
const settings = $('Buscar Configuracoes1').first().json;
// Pega a saída do nó com os dados básicos da empresa (nome, id, etc)
const company = $('Buscar Nome da Empresa1').first().json;

// 2. TRATAMENTO DOS DADOS (Evitando erros caso o banco de dados retorne Array ou Objeto direto)
// Se 'settings' for uma lista, pega o primeiro item. Se não, usa ele mesmo (sd = settings data)
const sd = Array.isArray(settings) ? settings[0] : settings;
// Mesma lógica para os dados da empresa (cd = company data)
const cd = Array.isArray(company) ? company[0] : company;

// 3. PREPARAÇÃO DOS HORÁRIOS
// Extrai o campo de horários. Se ele vier vazio/nulo, usa um objeto vazio {} para o código não quebrar
const openingHours = sd?.opening_hours || {};

// 4. IDENTIFICAÇÃO DO MOMENTO ATUAL (Fuso Horário do Brasil)
// Cria uma data com o horário exato de agora, forçando o fuso horário de São Paulo (evita bugs de servidor em outro país)
const now = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' }));

// Mapeia os dias da semana do JavaScript (que vão de 0 a 6) para os nomes em inglês que você usa no banco de dados
const dayMap = ['sun','mon','tue','wed','thu','fri','sat'];

// Pega o número do dia de hoje (ex: 1 para segunda-feira) e busca o nome no mapa (ex: 'mon')
const dayKey = dayMap[now.getDay()];

// Pega apenas a configuração de horário específica para o dia de hoje
const todayConfig = openingHours[dayKey];

// 5. CÁLCULO SE ESTÁ DENTRO OU FORA DO HORÁRIO COMERCIAL
// Começamos assumindo que estamos dentro do horário (true)
let inHours = true;

// Se existir uma configuração para o dia de hoje no banco de dados, faz as validações:
if (todayConfig) {
  // Se o dia de hoje estiver marcado como inativo (ex: domingo fechado), define inHours como falso (fora do horário)
  if (!todayConfig.active) { 
    inHours = false; 
  }
  // Se estiver ativo, vamos calcular se a hora atual está entre a abertura e o fechamento
  else {
    // Pega a hora de abertura (ou '08:00' por padrão). Divide em 'oh' (hora) e 'om' (minuto) e converte para número
    const [oh,om] = (todayConfig.open||'08:00').split(':').map(Number);
    // Pega a hora de fechamento (ou '18:00' por padrão). Divide em 'ch' (hora) e 'cm' (minuto) e converte para número
    const [ch,cm] = (todayConfig.close||'18:00').split(':').map(Number);

    // Converte a hora atual inteira para minutos (ex: 10:30 vira 10*60 + 30 = 630 minutos). Isso facilita muito a conta matemática.
    const cur = now.getHours()*60+now.getMinutes();

    // Define inHours como 'true' se os minutos atuais forem maiores/iguais ao horário de abertura E menores/iguais ao fechamento
    inHours = cur >= oh*60+om && cur <= ch*60+cm;
  }
}

// 6. RETORNO DOS DADOS PARA O N8N
// Junta todo o contexto anterior (...ctx) com as novas informações mapeadas e envia para o próximo nó
return [{ 
  json: { 
    ...ctx, 
    company_name: cd?.name || 'Empresa', // Nome da empresa ou um padrão
    welcome_message: sd?.welcome_message || 'Ola! Como posso ajudar?', // Mensagem de boas-vindas do BD
    fallback_message: sd?.fallback_message || 'Nao entendi. Pode repetir?', // Mensagem de erro do BD
    off_hours_message: sd?.off_hours_message || 'Estamos fora do horario de atendimento.', // Mensagem de ausência
    inHours // Variável booleana (true/false) informando se a empresa está aberta agora
  } 
}];

let lead;
try { const c = $('Criar Novo Lead1').first().json; lead = Array.isArray(c) ? c[0] : c; }
catch { const f = $('Buscar Lead1').first().json; lead = Array.isArray(f) ? f[0] : f; }
const ctx = $('Montar Contexto da Empresa1').first().json;
const hr = $('Verificar Horario e Montar Dados1').first().json;
return [{ json: { ...ctx, company_name: hr.company_name, welcome_message: hr.welcome_message, fallback_message: hr.fallback_message, lead_id: lead.id, lead_name: lead.name, lead_status: lead.current_status, is_new_lead: lead.current_status === 'new' } }];

let cid;
let active_flow_id = null;
let current_flow_step_id = null;
let isNewConversation = false;

try {
  const c = $('Criar Nova Conversa1').first().json;
  const arr = Array.isArray(c) ? c : [c];
  cid = arr[0].id;
  isNewConversation = true;
} catch {
  const f = $('Buscar Conversa Ativa1').first().json;
  const arr = Array.isArray(f) ? f : [f];
  cid = arr[0].id;
  active_flow_id = arr[0].active_flow_id;
  current_flow_step_id = arr[0].current_flow_step_id;
  isNewConversation = false;
}

return [{ 
  json: { 
    ...$('Consolidar Lead1').first().json, 
    conversation_id: cid, 
    active_flow_id,
    current_flow_step_id,
    is_new_conversation: isNewConversation 
  } 
}];

const r = $input.first().json;
const ctx = $('Montar Prompt para IA1').first().json;
const reply = r?.choices?.[0]?.message?.content || ctx.fallback_message || 'Nao consegui processar. Tente novamente.';
return [{ json: { ...ctx, reply } }];

const ctx = $('Consolidar Conversa1').first().json;
const historyRaw = $('Buscar Historico1').first().json;
const faqsRaw = $('Buscar FAQs1').first().json;
const productsRaw = $('Buscar Produtos1').first().json;

// Garantir que são arrays
const history = (Array.isArray(historyRaw) ? historyRaw : []).reverse();
const faqs = Array.isArray(faqsRaw) ? faqsRaw : [];
const products = Array.isArray(productsRaw) ? productsRaw : [];

// Montar as strings de contexto
const faqCtx = faqs.length > 0 ? faqs.map(f => `P: ${f.question}\nR: ${f.answer}`).join('\n\n') : 'Nenhuma FAQ cadastrada.';
const prodCtx = products.length > 0 ? products.map(p => { 
  let l = `- ${p.name}`; 
  if (p.description) l += `: ${p.description}`; 
  if (p.price) l += ` (R$ ${parseFloat(p.price).toFixed(2)})`; 
  return l; 
}).join('\n') : 'Nenhum produto cadastrado.';

// Montar o histórico de mensagens formatado para a IA
const histMsgs = history.map(m => ({ 
  role: m.sender_type === 'bot' ? 'assistant' : 'user', 
  content: String(m.content || '') 
}));

// Montar o System Prompt
const systemPrompt = `Você é um assistente de atendimento da empresa "${ctx.company_name}". Ajude clientes de forma cordial, objetiva e natural.

REGRAS:
- Responda SEMPRE em português brasileiro
- Seja conciso (máximo 3 parágrafos)
- Use emojis com moderação
- NÃO invente informações
- Se não souber, use o fallback
- Se o cliente quiser um humano, informe que vai encaminhar

FAQ:
${faqCtx}

PRODUTOS/SERVIÇOS:
${prodCtx}

FALLBACK: ${ctx.fallback_message || 'Um momento, vou transferir você para um atendente.'}`;

// Juntar as mensagens na ordem correta: System -> Histórico -> Mensagem Atual do Usuário
const messagesArray = [
  { role: "system", content: systemPrompt },
  ...histMsgs,
  { role: "user", content: String(ctx.message || '') }
];

// Criar o Body exato que a API exige (usando o Gemini 2.5 Flash)
const geminiPayload = {
  model: "gemini-2.5-flash", 
  messages: messagesArray,
  max_tokens: 600,
  temperature: 0.7
};

// Retornar os dados originais + o payload pronto
return [{ 
  json: { 
    ...ctx, 
    systemPrompt, 
    geminiPayload 
  } 
}];

const ctx = $("Consolidar Conversa1").first().json;
const allItems = $input.all();
const flowsRaw = allItems.map(i => i.json);
// Filter out empty/null items (alwaysOutputData can pass empty items)
const flows = flowsRaw.filter(f => f && f.id);
const message = String(ctx.message || "").toLowerCase().trim();

// Sort by priority (lower number = higher priority)
const sorted = flows.sort((a, b) => (a.priority || 10) - (b.priority || 10));

for (const flow of sorted) {
  const keywords = flow.trigger_keywords || [];
  const triggerType = flow.trigger_type || "keyword";
  const steps = Array.isArray(flow.steps)
    ? flow.steps.sort((a, b) => a.step_order - b.step_order)
    : [];

  // Skip flows with no runnable steps
  if (steps.length === 0) continue;

  // first_message: ONLY fires on a brand-new conversation (not every message from a new lead)
  // ctx.is_new_conversation = true only when Criar Nova Conversa1 ran (new convo started)
  // ctx.is_new_lead = true only when lead.current_status === 'new'
  if (triggerType === "first_message") {
    if (ctx.is_new_conversation === true && ctx.is_new_lead === true) {
      return [{ json: { ...ctx, active_flow: flow, flow_steps: steps, use_ai: false } }];
    }
    // Don't match first_message for existing conversations — fall through to next flow
    continue;
  }

  // keyword: check if any keyword appears in the message
  if (triggerType === "keyword" && keywords.length > 0) {
    const triggered = keywords.some(kw => {
      const kwLower = String(kw).toLowerCase().trim();
      return message.includes(kwLower);
    });
    if (triggered) {
      return [{ json: { ...ctx, active_flow: flow, flow_steps: steps, use_ai: false } }];
    }
  }
}

// No flow matched — use AI
return [{ json: { ...ctx, active_flow: null, flow_steps: [], use_ai: true } }];

const ctx = $json;
const flows = $("Buscar Fluxos Ativos").first().json;
const flowsArr = Array.isArray(flows) ? flows : [flows];

let steps = ctx.flow_steps || [];
let flow = ctx.active_flow || {};
const config = flow.config || {};
const isContinuing = ctx.is_continuing;
const currentStepId = ctx.current_flow_step_id;
const userMessage = String(ctx.message || "").trim();

let startIndex = 0;
let messagesToSend = [];
let pausedAtStep = null;
let ended = false;
let newActiveFlowId = flow.id;
let isInvalidOption = false;

if (isContinuing && currentStepId) {
  const currentIdx = steps.findIndex(s => s.id === currentStepId);
  if (currentIdx >= 0) {
    const pausedStep = steps[currentIdx];

    if (pausedStep.step_type === "condition") {
      const routes = (pausedStep.metadata && pausedStep.metadata.routes) ? pausedStep.metadata.routes : {};
      let matchedFlowId = null;
      for (const [key, targetId] of Object.entries(routes)) {
        if (userMessage.toLowerCase() === String(key).toLowerCase() || userMessage.toLowerCase().startsWith(String(key).toLowerCase() + " ")) {
          matchedFlowId = targetId;
          break;
        }
      }

      if (matchedFlowId) {
        const targetFlow = flowsArr.find(f => f.id === matchedFlowId);
        if (targetFlow) {
          flow = targetFlow;
          steps = Array.isArray(targetFlow.steps) ? targetFlow.steps.sort((a, b) => a.step_order - b.step_order) : [];
          startIndex = 0;
          newActiveFlowId = targetFlow.id;
        } else {
          isInvalidOption = true;
        }
      } else {
        isInvalidOption = true;
      }

      if (isInvalidOption) {
        messagesToSend.push("Desculpe, opção inválida. Por favor, tente novamente.");
        pausedAtStep = pausedStep;
        startIndex = steps.length;
      }
    } else {
      startIndex = currentIdx + 1;
    }
  }
}

for (let i = startIndex; i < steps.length; i++) {
  const step = steps[i];

  if (step.step_type === "end") {
    ended = true;
    let content = String(step.message || "");
    if (content.trim()) messagesToSend.push(content);
    break;
  }

  let content = String(step.message || "");
  for (const [key, val] of Object.entries(config)) {
    content = content.replace(new RegExp("{{" + key + "}}", "g"), String(val));
  }
  content = content
    .replace(/{{company_name}}/g, ctx.company_name || "")
    .replace(/{{lead_name}}/g, ctx.lead_name || ctx.name || "Cliente")
    .replace(/{{nome}}/g, ctx.lead_name || ctx.name || "Cliente");

  if (content.trim()) {
    messagesToSend.push(content);
  }

  if (step.step_type === "question" || step.step_type === "catalog" || step.step_type === "condition") {
    pausedAtStep = step;
    break; 
  }
}

if (messagesToSend.length === 0 && !ended && pausedAtStep && !isInvalidOption) {
  if (pausedAtStep.step_type === "condition") {
    messagesToSend.push("Por favor, selecione uma opção.");
  } else {
    messagesToSend.push("Por favor, responda à pergunta.");
  }
}

const payload = { 
  ...ctx,
  messages_to_send: messagesToSend,
  new_active_flow_id: ended ? null : newActiveFlowId,
  new_current_step_id: (pausedAtStep && pausedAtStep.id) ? pausedAtStep.id : null,
  flow_executed: true
};

return [{ json: payload }];

